"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[57738],{94832:e=>{e.exports=JSON.parse('{"tag":{"label":"migration","permalink":"/dst-api-webdocs/docs/tags/migration","allTagsPath":"/dst-api-webdocs/docs/tags","count":12,"items":[{"id":"game-scripts/prefabs/cave_exit","title":"Cave Exit","description":"Manages the visual and logical state of the cave exit portal, synchronizing its animation and status with world migration events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cave_exit"},{"id":"game-scripts/prefabs/deer","title":"Deer","description":"Manages the behavior, combat, and lifecycle of deer entities, including antler growth, migration, and gemmed variants that cast spells.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deer"},{"id":"game-scripts/components/migrationmanager","title":"Migrationmanager","description":"Manages population groups of migratory creatures (e.g., Crystal-Crested Buzzards) by tracking their location in world nodes, migration paths, and group membership.","permalink":"/dst-api-webdocs/docs/game-scripts/components/migrationmanager"},{"id":"game-scripts/components/migrationpetowner","title":"Migrationpetowner","description":"Provides a lightweight mechanism for an inventory item to store and retrieve one or more associated migration-capable pets via a callback function.","permalink":"/dst-api-webdocs/docs/game-scripts/components/migrationpetowner"},{"id":"game-scripts/components/migrationpetsoverrider","title":"Migrationpetsoverrider","description":"Provides a mechanism to override positioning logic for migration pets spawned by the player spawner system.","permalink":"/dst-api-webdocs/docs/game-scripts/components/migrationpetsoverrider"},{"id":"game-scripts/components/mutatedbuzzardcircler","title":"Mutatedbuzzardcircler","description":"Controls the circling behavior of a mutated buzzard around a target entity, managing movement, migration, and interactions like flare detonations and corpse landings.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mutatedbuzzardcircler"},{"id":"game-scripts/components/mutatedbuzzardmanager","title":"Mutatedbuzzardmanager","description":"Manages mutated buzzard gestalt populations, tracks circling shadows for players, and controls spawning/dropping behavior in response to rift states, megaflares, and deaths.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mutatedbuzzardmanager"},{"id":"game-scripts/prefabs/oceanwhirlbigportal","title":"Oceanwhirlbigportal","description":"Controls the big ocean whirlpool portal that transports entities to the Caves, manages visual layers, sound, wave blocking, and looting behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanwhirlbigportal"},{"id":"game-scripts/brains/penguinbrain","title":"Penguinbrain","description":"AI brain governing penguin behavior including egg laying, retrieval, foraging, fleeing from predators, and group migration.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/penguinbrain"},{"id":"game-scripts/components/playerspawner","title":"Playerspawner","description":"Manages player spawning logic, including position selection, spawn protection, and migration handling in the master simulation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playerspawner"},{"id":"game-scripts/components/teleporter","title":"Teleporter","description":"Manages inter- and intra-world teleportation of entities, including followers and items, with support for migration, camera transitions, and walkable offset alignment.","permalink":"/dst-api-webdocs/docs/game-scripts/components/teleporter"},{"id":"game-scripts/components/worldmigrator","title":"Worldmigrator","description":"Manages portal-based world migration logic, including status validation, item migration rules, and event triggering for players and items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldmigrator"}],"unlisted":false}}')}}])